import { useEffect, useState, useCallback } from "react";
import { useNavigate } from "react-router-dom";
import api from "../api";
import {
  LogOut,
  Compass,
  Plus,
  Pencil,
  Trash2,
  Mountain,
  DollarSign,
  X,
  Loader2,
  Eye,
  EyeOff,
  ChevronDown,
  ChevronUp,
  Award,
  MapPin,
  Clock,
  TrendingUp,
  Activity,
} from "lucide-react";
import { useLogoutHandler } from "../hooks/useLogoutHandler";
import LogoutModal from "../components/LogoutModal";
import { useAuth } from "../context/AuthContext";
import { getToken } from "../tokenStore";

const API = "http://localhost:5000/api";

/* ─────────────────────────────────────────
   EXPERIENCE BADGE
───────────────────────────────────────── */
const ExperienceBadge = ({ level }) => {
  const config = {
    beginner: {
      bg: "bg-emerald-50 border-emerald-200",
      text: "text-emerald-700",
      label: "Beginner",
    },
    intermediate: {
      bg: "bg-amber-50 border-amber-200",
      text: "text-amber-700",
      label: "Intermediate",
    },
    expert: {
      bg: "bg-violet-50 border-violet-200",
      text: "text-violet-700",
      label: "Expert",
    },
  };

  const c = config[level] || config.beginner;

  return (
    <span
      className={`inline-flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-semibold border ${c.bg} ${c.text}`}
    >
      <Award className="h-3.5 w-3.5" />
      {c.label}
    </span>
  );
};

/* ─────────────────────────────────────────
   STAT CARD
───────────────────────────────────────── */
const StatCard = ({ icon: Icon, label, value, accent }) => {
  const accents = {
    blue: "from-blue-500 to-blue-600",
    emerald: "from-emerald-500 to-teal-500",
    amber: "from-amber-500 to-orange-500",
    purple: "from-violet-500 to-purple-600",
  };
  return (
    <div className="relative bg-white rounded-2xl p-5 border border-gray-100 shadow-sm overflow-hidden group hover:shadow-md transition-shadow">
      <div
        className={`absolute -right-4 -top-4 w-20 h-20 rounded-full bg-gradient-to-br ${accents[accent]} opacity-10 group-hover:opacity-20 transition-opacity`}
      />
      <div className={`inline-flex p-2.5 rounded-xl bg-gradient-to-br ${accents[accent]} mb-3`}>
        <Icon className="h-5 w-5 text-white" />
      </div>
      <p className="text-2xl font-bold text-gray-900 font-mono">{value}</p>
      <p className="text-sm text-gray-500 mt-0.5">{label}</p>
    </div>
  );
};

/* ─────────────────────────────────────────
   ADD / EDIT TRAIL FORM
───────────────────────────────────────── */
const TrailForm = ({ trails, onSubmit, onCancel, initialData, isSubmitting }) => {
  const [form, setForm] = useState({
    trail_id: initialData?.trail_id || "",
    price_per_day: initialData?.price_per_day || "",
    experience_level: initialData?.experience_level || "",
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    onSubmit(form);
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4 overflow-y-auto">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-lg">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-gray-100 sticky top-0 bg-white rounded-t-2xl z-10">
          <h2 className="text-xl font-bold text-gray-900">
            {initialData ? "Edit Trail Assignment" : "Add Trail"}
          </h2>
          <button
            onClick={onCancel}
            className="p-2 hover:bg-gray-100 rounded-xl transition-colors"
          >
            <X className="h-5 w-5 text-gray-500" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-5">
          {/* Trail Selection */}
          {!initialData && (
            <div>
              <label className="block text-sm font-semibold text-gray-700 mb-1.5">
                Trail <span className="text-red-500">*</span>
              </label>
              <select
                name="trail_id"
                value={form.trail_id}
                onChange={handleChange}
                required
                className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent bg-gray-50 transition-colors"
              >
                <option value="">Select a trail...</option>
                {trails.map((trail) => (
                  <option key={trail.trail_id} value={trail.trail_id}>
                    {trail.trail_name} — {trail.region} ({trail.difficulty_level})
                  </option>
                ))}
              </select>
            </div>
          )}

          {/* Price Per Day */}
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1.5">
              Price Per Day (NPR) <span className="text-red-500">*</span>
            </label>
            <input
              type="number"
              name="price_per_day"
              value={form.price_per_day}
              onChange={handleChange}
              required
              min="0"
              step="0.01"
              placeholder="e.g. 3500"
              className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent bg-gray-50"
            />
          </div>

          {/* Experience Level */}
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1.5">
              Experience Level <span className="text-red-500">*</span>
            </label>
            <select
              name="experience_level"
              value={form.experience_level}
              onChange={handleChange}
              required
              className="w-full px-4 py-2.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent bg-gray-50 transition-colors"
            >
              <option value="">Select level...</option>
              <option value="beginner">Beginner</option>
              <option value="intermediate">Intermediate</option>
              <option value="expert">Expert</option>
            </select>
          </div>

          {/* Submit */}
          <div className="flex gap-3 pt-2">
            <button
              type="button"
              onClick={onCancel}
              className="flex-1 px-4 py-2.5 border border-gray-200 rounded-xl text-gray-700 font-semibold hover:bg-gray-50 transition-colors"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={isSubmitting}
              className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 bg-blue-600 hover:bg-blue-700 disabled:bg-blue-400 text-white rounded-xl font-semibold transition-colors"
            >
              {isSubmitting ? (
                <>
                  <Loader2 className="h-4 w-4 animate-spin" />
                  {initialData ? "Updating..." : "Adding..."}
                </>
              ) : initialData ? (
                "Update Assignment"
              ) : (
                "Add to Trail"
              )}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

/* ─────────────────────────────────────────
   DELETE CONFIRMATION MODAL
───────────────────────────────────────── */
const DeleteModal = ({ trailName, onConfirm, onCancel, isDeleting }) => (
  <div className="fixed inset-0 bg-black/50 backdrop-blur-sm z-50 flex items-center justify-center p-4">
    <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-6">
      <div className="flex items-center gap-3 mb-4">
        <div className="p-3 bg-red-100 rounded-xl">
          <Trash2 className="h-6 w-6 text-red-600" />
        </div>
        <div>
          <h3 className="text-lg font-bold text-gray-900">Remove from Trail</h3>
          <p className="text-sm text-gray-500">This action cannot be undone</p>
        </div>
      </div>
      <p className="text-gray-600 mb-6">
        Are you sure you want to remove yourself from <strong>"{trailName}"</strong>? Your pricing
        and assignment data will be permanently deleted.
      </p>
      <div className="flex gap-3">
        <button
          onClick={onCancel}
          className="flex-1 px-4 py-2.5 border border-gray-200 rounded-xl text-gray-700 font-semibold hover:bg-gray-50 transition-colors"
        >
          Cancel
        </button>
        <button
          onClick={onConfirm}
          disabled={isDeleting}
          className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 bg-red-600 hover:bg-red-700 disabled:bg-red-400 text-white rounded-xl font-semibold transition-colors"
        >
          {isDeleting ? (
            <>
              <Loader2 className="h-4 w-4 animate-spin" /> Removing...
            </>
          ) : (
            "Remove"
          )}
        </button>
      </div>
    </div>
  </div>
);

/* ─────────────────────────────────────────
   TRAIL CARD
───────────────────────────────────────── */
const TrailCard = ({ guideTrail, onEdit, onDelete, onToggleActive, expanded, onToggleExpand }) => {
  return (
    <div className={`bg-white rounded-2xl shadow-sm border overflow-hidden hover:shadow-md transition-shadow ${!guideTrail.is_active ? 'border-gray-200 opacity-75' : 'border-gray-100'}`}>
      {/* Card Header */}
      <div className="relative">
        <div className={`w-full h-32 flex items-center justify-center ${
          guideTrail.is_active
            ? 'bg-gradient-to-br from-blue-500 to-indigo-600'
            : 'bg-gradient-to-br from-gray-400 to-gray-500'
        }`}>
          <Mountain className="h-14 w-14 text-white/30" />
        </div>
        <div className="absolute top-3 left-3">
          <ExperienceBadge level={guideTrail.experience_level} />
        </div>
        {!guideTrail.is_active && (
          <div className="absolute top-3 right-3 bg-gray-800/80 text-white text-xs px-2 py-1 rounded-full">
            Inactive
          </div>
        )}
      </div>

      {/* Card Body */}
      <div className="p-5">
        <div className="flex items-start justify-between mb-2">
          <h3 className="text-lg font-bold text-gray-900 leading-tight">
            {guideTrail.trail_name}
          </h3>
          <button onClick={() => onToggleExpand(guideTrail.id)} className="ml-2 mt-0.5">
            {expanded ? (
              <ChevronUp className="h-5 w-5 text-gray-400" />
            ) : (
              <ChevronDown className="h-5 w-5 text-gray-400" />
            )}
          </button>
        </div>

        <div className="flex items-center gap-1.5 text-sm text-gray-500 mb-3">
          <MapPin className="h-3.5 w-3.5" />
          {guideTrail.region}
        </div>

        <div className="flex items-center gap-4 text-sm text-gray-700 mb-4">
          <span className="flex items-center gap-1">
            <DollarSign className="h-3.5 w-3.5 text-emerald-500" />
            NPR {Number(guideTrail.price_per_day).toLocaleString()}/day
          </span>
          {guideTrail.difficulty_level && (
            <span className="flex items-center gap-1">
              <TrendingUp className="h-3.5 w-3.5 text-blue-500" />
              {guideTrail.difficulty_level}
            </span>
          )}
        </div>

        {/* Expanded Details */}
        {expanded && (
          <div className="border-t border-gray-100 pt-4 mt-2 space-y-3">
            {guideTrail.duration_days && (
              <div className="flex items-center gap-1.5 text-sm text-gray-600">
                <Clock className="h-3.5 w-3.5" />
                {guideTrail.duration_days} days duration
              </div>
            )}
            <div className="flex items-center gap-1.5 text-sm text-gray-600">
              <Activity className="h-3.5 w-3.5" />
              Status: {guideTrail.is_active ? "Active — visible to trekkers" : "Inactive — hidden from trekkers"}
            </div>
            <p className="text-xs text-gray-400">
              Added: {new Date(guideTrail.created_at).toLocaleDateString("en-US", { year: "numeric", month: "short", day: "numeric" })}
            </p>
          </div>
        )}

        {/* Actions */}
        <div className="flex gap-2 mt-4 pt-3 border-t border-gray-100">
          <button
            onClick={() => onEdit(guideTrail)}
            className="flex-1 flex items-center justify-center gap-1.5 px-3 py-2 text-sm font-semibold text-blue-600 bg-blue-50 hover:bg-blue-100 rounded-xl transition-colors"
          >
            <Pencil className="h-3.5 w-3.5" /> Edit
          </button>
          <button
            onClick={() => onToggleActive(guideTrail.id)}
            className={`flex items-center justify-center gap-1.5 px-3 py-2 text-sm font-semibold rounded-xl transition-colors ${
              guideTrail.is_active
                ? "text-amber-600 bg-amber-50 hover:bg-amber-100"
                : "text-emerald-600 bg-emerald-50 hover:bg-emerald-100"
            }`}
            title={guideTrail.is_active ? "Deactivate" : "Activate"}
          >
            {guideTrail.is_active ? <EyeOff className="h-3.5 w-3.5" /> : <Eye className="h-3.5 w-3.5" />}
          </button>
          <button
            onClick={() => onDelete(guideTrail)}
            className="flex items-center justify-center gap-1.5 px-3 py-2 text-sm font-semibold text-red-600 bg-red-50 hover:bg-red-100 rounded-xl transition-colors"
          >
            <Trash2 className="h-3.5 w-3.5" />
          </button>
        </div>
      </div>
    </div>
  );
};

/* ─────────────────────────────────────────
   GUIDE DASHBOARD
───────────────────────────────────────── */
const GuideDashboard = () => {
  const navigate = useNavigate();
  const [user, setUser] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const { handleLogout, handleStayLoggedIn, showLogoutModal, setShowLogoutModal } =
    useLogoutHandler();
  const { user: authUser, loading } = useAuth();

  const [guideTrails, setGuideTrails] = useState([]);
  const [trails, setTrails] = useState([]);
  const [trailsLoading, setTrailsLoading] = useState(false);
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingTrail, setEditingTrail] = useState(null);
  const [deletingTrail, setDeletingTrail] = useState(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [expandedCard, setExpandedCard] = useState(null);
  const [notification, setNotification] = useState(null);

  // Auth check
  useEffect(() => {
    if (loading) return;
    if (!getToken() || !authUser) { navigate("/login", { replace: true }); return; }
    if (authUser.user_type !== "guide") { navigate("/login", { replace: true }); return; }
    setUser(authUser);
    setIsLoading(false);
  }, [loading, navigate, authUser]);

  // Show notification
  const showNotification = (message, type = "success") => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 4000);
  };

  // Fetch guide's trail assignments
  const fetchGuideTrails = useCallback(async () => {
    setTrailsLoading(true);
    try {
      const res = await api.get(`${API}/guides/my-trails`);
      setGuideTrails(res.data.guide_trails);
    } catch (err) {
      console.error("Error fetching guide trails:", err);
      showNotification("Failed to load trail assignments", "error");
    } finally {
      setTrailsLoading(false);
    }
  }, []);

  // Fetch trails for dropdown
  const fetchTrails = useCallback(async () => {
    try {
      const res = await api.get(`${API}/guides/trails-list`);
      setTrails(res.data.trails);
    } catch (err) {
      console.error("Error fetching trails:", err);
    }
  }, []);

  useEffect(() => {
    if (!isLoading && user) {
      fetchGuideTrails();
      fetchTrails();
    }
  }, [isLoading, user, fetchGuideTrails, fetchTrails]);

  // Add to trail
  const handleAdd = async (formData) => {
    setIsSubmitting(true);
    try {
      await api.post(`${API}/guides/trails`, formData);
      showNotification("Successfully added to trail!");
      setShowAddForm(false);
      fetchGuideTrails();
    } catch (err) {
      console.error("Error adding to trail:", err);
      showNotification(err.response?.data?.message || "Failed to add to trail", "error");
    } finally {
      setIsSubmitting(false);
    }
  };

  // Update trail assignment
  const handleUpdate = async (formData) => {
    setIsSubmitting(true);
    try {
      await api.put(`${API}/guides/trails/${editingTrail.id}`, formData);
      showNotification("Trail assignment updated!");
      setEditingTrail(null);
      fetchGuideTrails();
    } catch (err) {
      console.error("Error updating trail assignment:", err);
      showNotification(err.response?.data?.message || "Failed to update", "error");
    } finally {
      setIsSubmitting(false);
    }
  };

  // Delete trail assignment
  const handleDelete = async () => {
    setIsDeleting(true);
    try {
      await api.delete(`${API}/guides/trails/${deletingTrail.id}`);
      showNotification("Removed from trail successfully.");
      setDeletingTrail(null);
      fetchGuideTrails();
    } catch (err) {
      console.error("Error removing from trail:", err);
      showNotification(err.response?.data?.message || "Failed to remove", "error");
    } finally {
      setIsDeleting(false);
    }
  };

  // Toggle active
  const handleToggleActive = async (id) => {
    try {
      const res = await api.patch(`${API}/guides/trails/${id}/toggle-active`, {});
      showNotification(res.data.message);
      fetchGuideTrails();
    } catch (err) {
      console.error("Error toggling status:", err);
      showNotification("Failed to toggle status", "error");
    }
  };

  // Stats
  const stats = {
    total: guideTrails.length,
    active: guideTrails.filter((t) => t.is_active).length,
    inactive: guideTrails.filter((t) => !t.is_active).length,
    avgPrice:
      guideTrails.length > 0
        ? Math.round(guideTrails.reduce((sum, t) => sum + Number(t.price_per_day), 0) / guideTrails.length)
        : 0,
  };

  if (isLoading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-gray-50 to-blue-50">
        <div className="flex flex-col items-center gap-3">
          <Loader2 className="h-10 w-10 text-blue-600 animate-spin" />
          <p className="text-gray-500 font-medium">Loading dashboard...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-blue-50">
      {/* Notification Toast */}
      {notification && (
        <div
          className={`fixed top-4 right-4 z-[100] px-5 py-3 rounded-xl shadow-lg text-sm font-semibold transition-all ${
            notification.type === "error"
              ? "bg-red-600 text-white"
              : "bg-emerald-600 text-white"
          }`}
        >
          {notification.message}
        </div>
      )}

      {/* Nav */}
      <nav className="bg-white shadow-sm border-b sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center">
              <Compass className="h-8 w-8 text-blue-600 mr-2" />
              <span className="text-xl font-bold text-gray-900">OffTrailNepal</span>
              <span className="ml-2 px-2 py-0.5 bg-blue-100 text-blue-700 text-xs font-semibold rounded-full">
                Guide
              </span>
            </div>
            <button
              onClick={setShowLogoutModal}
              className="flex items-center space-x-2 px-4 py-2 bg-red-600 hover:bg-red-700 text-white rounded-xl font-semibold transition-colors duration-300"
            >
              <LogOut className="h-5 w-5" />
              <span className="hidden sm:inline">Logout</span>
            </button>
          </div>
        </div>
      </nav>

      {/* Main Content */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Welcome */}
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between mb-8 gap-4">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">Guide Dashboard</h1>
            <p className="text-gray-500 mt-1">
              Welcome back, <span className="font-semibold text-gray-700">{user?.full_name || "Guide"}</span> 🧭
            </p>
          </div>
          <button
            onClick={() => setShowAddForm(true)}
            className="flex items-center gap-2 px-5 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-semibold shadow-sm hover:shadow transition-all"
          >
            <Plus className="h-5 w-5" />
            Add Trail
          </button>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          <StatCard icon={Mountain} label="Total Trails" value={stats.total} accent="blue" />
          <StatCard icon={Eye} label="Active Trails" value={stats.active} accent="emerald" />
          <StatCard icon={EyeOff} label="Inactive Trails" value={stats.inactive} accent="amber" />
          <StatCard
            icon={DollarSign}
            label="Avg Price/Day"
            value={stats.avgPrice > 0 ? `NPR ${stats.avgPrice.toLocaleString()}` : "—"}
            accent="purple"
          />
        </div>

        {/* Trail Cards */}
        {trailsLoading ? (
          <div className="flex items-center justify-center py-20">
            <Loader2 className="h-8 w-8 text-blue-600 animate-spin" />
          </div>
        ) : guideTrails.length === 0 ? (
          <div className="bg-white rounded-2xl shadow-sm border p-12 text-center">
            <Mountain className="h-16 w-16 text-gray-300 mx-auto mb-4" />
            <h2 className="text-xl font-bold text-gray-900 mb-2">No Trail Assignments Yet</h2>
            <p className="text-gray-500 mb-6">
              Start adding trails to appear in the guide marketplace for trekkers.
            </p>
            <button
              onClick={() => setShowAddForm(true)}
              className="inline-flex items-center gap-2 px-5 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-xl font-semibold transition-colors"
            >
              <Plus className="h-5 w-5" />
              Add Your First Trail
            </button>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {guideTrails.map((gt) => (
              <TrailCard
                key={gt.id}
                guideTrail={gt}
                onEdit={(data) => setEditingTrail(data)}
                onDelete={(data) => setDeletingTrail(data)}
                onToggleActive={handleToggleActive}
                expanded={expandedCard === gt.id}
                onToggleExpand={(id) => setExpandedCard(expandedCard === id ? null : id)}
              />
            ))}
          </div>
        )}
      </div>

      {/* Modals */}
      {showAddForm && (
        <TrailForm
          trails={trails}
          onSubmit={handleAdd}
          onCancel={() => setShowAddForm(false)}
          isSubmitting={isSubmitting}
        />
      )}

      {editingTrail && (
        <TrailForm
          trails={trails}
          onSubmit={handleUpdate}
          onCancel={() => setEditingTrail(null)}
          initialData={editingTrail}
          isSubmitting={isSubmitting}
        />
      )}

      {deletingTrail && (
        <DeleteModal
          trailName={deletingTrail.trail_name}
          onConfirm={handleDelete}
          onCancel={() => setDeletingTrail(null)}
          isDeleting={isDeleting}
        />
      )}

      {/* Logout Confirmation Modal */}
      <LogoutModal
        isOpen={showLogoutModal}
        onConfirm={handleLogout}
        onCancel={handleStayLoggedIn}
      />
    </div>
  );
};

export default GuideDashboard;
